const net = require("net");

const PROXY_HOST = "127.0.0.1";
const PROXY_PORT = 1500;

const RAW_HEX = ``;

function hexToBuffer(hex) {
  return Buffer.from(hex.replace(/\s/g, ""), "hex");
}

const client = net.createConnection(PROXY_PORT, PROXY_HOST, () => {
  console.log("🔥 Fake collector connected");

  setInterval(() => {
    const buffer = hexToBuffer(RAW_HEX);

    console.log("\n📤 SEND:");
    console.log(buffer.toString("hex"));

    client.write(buffer);
  }, 3000);
});

client.on("data", (data) => {
  console.log("📥 Response:", data.toString("hex"));
});